    count_up_to(1) => []
    count_up_to(18) => [2,3,5,7,11,13,17]
    """
    result = []
    for number in range(2, n):
        for divisor in range(2, number):
            if number % divisor == 0:
                break
        else:
            result.append(number)
    return result

