        if letter in result:
            result[letter] += 1
        else:
            result[letter] = 1

    max = 0
    result2 = {}
    for letter in result:
        if result[letter] > max:
            max = result[letter]
            result2 = {}
            result2[letter] = result[letter]
        elif result[letter] == max:
            result2[letter] = result[letter]

    return result2
